using Rocks.Exceptions;
using Rocks.Extensions;

namespace Rocks;

/// <summary>
/// The base class for all expectation types.
/// </summary>
/// <remarks>
/// This type is designed to be used from code generated by Rocks,
/// and is not intended for general use. Please refrain from
/// referencing it for any other purposes, as its implementation may change.
/// </remarks>
public abstract class Expectations
{
	/// <summary>
	/// Removes the handler wrapped by <paramref name="adornments"/> from <paramref name="handlers"/>.
	/// </summary>
	/// <typeparam name="TAdornments">The adornments type.</typeparam>
	/// <typeparam name="THandler">The handler type.</typeparam>
	/// <typeparam name="TCallback">The callback type.</typeparam>
	/// <param name="adornments">The adornment to get the handler from.</param>
	/// <param name="handlers">A list of handlers.</param>
	protected static void Remove<TAdornments, THandler, TCallback>(TAdornments adornments, List<THandler> handlers)
		where TAdornments : Adornments<TAdornments, THandler, TCallback>
		where THandler : Handler<TCallback>
		where TCallback : Delegate
	{
		ArgumentNullException.ThrowIfNull(adornments);
		ArgumentNullException.ThrowIfNull(handlers);
		_ = handlers.Remove(adornments.Handler);
	}

	/// <summary>
	/// Verifies the expectations.
	/// </summary>
	public abstract void Verify();

	/// <summary>
	/// Verifies handlers.
	/// </summary>
	/// <param name="handlers">A list of handlers to verify</param>
	/// <param name="memberIdentifier">The member identifier for the handlers</param>
	/// <returns>A list of failed expectations</returns>
	protected IEnumerable<string> Verify<THandler>(Handlers<THandler> handlers, uint memberIdentifier)
		where THandler : Handler =>
			handlers.Where(_ => _.ExpectedCallCount != _.CallCount)
				.Select(_ =>
				{
					var member = this.MockType!.GetMemberDescription(memberIdentifier);
					return $"Mock type: {this.MockType!.FullName}, member: {member}, message: The expected call count is incorrect. Expected: {_.ExpectedCallCount}, received: {_.CallCount}.";
				});

	/// <summary>
	/// Gets or sets the mock type.
	/// </summary>
	protected Type? MockType { get; set; }

	/// <summary>
	/// Gets or sets the flag to determine if a mock threw an exception, like <see cref="ExpectationException"/>.
	/// </summary>
	public bool WasExceptionThrown { get; protected set; }

	/// <summary>
	/// Gets or sets the flag to determine if an mock instance was created.
	/// </summary>
	public bool WasInstanceInvoked { get; protected set; }
}